SELECT FROM announcement WHERE deleted = 0
AND title LIKE CONCAT('%', #{query.title}, '%')
AND creator LIKE CONCAT('%', #{query.creator}, '%')
AND type = #{query.type}
ORDER BY create_time DESC LIMIT #{offset}, #{pageSize}

SELECT username FROM user WHERE id IN (
    SELECT user_id FROM announcement_read WHERE announcement_id = #{id}
)
